#include <iostream>
#include <vector>

class DataBuffer {
public:
    DataBuffer(size_t size) : buffer(size) {}
    void set_val(size_t idx, int val) {
        if (idx < buffer.size()) {
            buffer[idx] = val;
        }
    }
    int get_val(size_t idx) {
        return (idx < buffer.size()) ? buffer[idx] : -1;
    }
private:
    std::vector<int> buffer;
};

int main() {
    DataBuffer db(10);
    db.set_val(5, 42);
    std::cout << "Value at 5: " << db.get_val(5) << std::endl;
    return 0;
}
```
